import{c as e,a7 as l,y as d,B as r}from"./chunks/framework.3cjvm90C.js";const g=JSON.parse('{"title":"LLM 性能优化方法论（基于 MindSpeed LLM）","description":"基于 MindSpeed LLM 总结大模型训练性能瓶颈分类与计算、显存、通信三大维度的优化策略","frontmatter":{"title":"LLM 性能优化方法论（基于 MindSpeed LLM）","description":"基于 MindSpeed LLM 总结大模型训练性能瓶颈分类与计算、显存、通信三大维度的优化策略"},"headers":[],"relativePath":"ascend/mindspeed_llm.md","filePath":"ascend/mindspeed_llm.md","lastUpdated":1782447613000}'),i={name:"ascend/mindspeed_llm.md"};function o(a,t,n,s,h,c){return l(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="mindspeed-llm-性能优化" tabindex="-1">MindSpeed LLM 性能优化 <a class="header-anchor" href="#mindspeed-llm-性能优化" aria-label="Permalink to “MindSpeed LLM 性能优化”">​</a></h1><h2 id="llm-性能优化方法论-基于-mindspeed-llm" tabindex="-1">LLM 性能优化方法论（基于 MindSpeed LLM） <a class="header-anchor" href="#llm-性能优化方法论-基于-mindspeed-llm" aria-label="Permalink to “LLM 性能优化方法论（基于 MindSpeed LLM）”">​</a></h2><blockquote><p><strong>核心目标</strong>：在不同业务场景下，识别性能瓶颈（Device Bound / Host Bound），并应用针对性的加速与显存优化策略。</p></blockquote><h3 id="一、性能瓶颈分类与典型场景" tabindex="-1">一、性能瓶颈分类与典型场景 <a class="header-anchor" href="#一、性能瓶颈分类与典型场景" aria-label="Permalink to “一、性能瓶颈分类与典型场景”">​</a></h3><table tabindex="0"><thead><tr><th>业务阶段</th><th>模型类型</th><th>主要瓶颈</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>预训练</strong></td><td>稠密模型（如 Llama, GPT-Qwen）</td><td>Device Bound</td><td>计算密集，受限于芯片算力</td></tr><tr><td></td><td>MoE 模型（如 Mixtral, Deepseek）</td><td>Device Bound（Dropless）或 Host Bound（Drop）</td><td>MoE 路由/通信开销大</td></tr><tr><td><strong>全参微调</strong></td><td>静态/动态序列</td><td>Device Bound</td><td>显存压力大，计算密集</td></tr><tr><td><strong>LoRA 微调</strong></td><td>静态/动态序列</td><td>Host Bound</td><td>小参数更新，通信或 CPU 成瓶颈</td></tr><tr><td><strong>偏好对齐（RLHF）</strong></td><td>Actor/Critic/RM</td><td>Device Bound</td><td>多模型协同，显存与计算压力</td></tr><tr><td><strong>在线推理 &amp; 搜索</strong></td><td>—</td><td>Host Bound</td><td>请求调度、KV Cache 管理、I/O 延迟</td></tr></tbody></table><blockquote><p>✅ <strong>关键洞察</strong>：</p><ul><li><strong>稠密模型</strong>通常为 <strong>Device Bound</strong>（算力/显存受限）；</li><li><strong>MoE 模型</strong>需关注 <strong>Token Dispatch 开销</strong>（AllGather vs All2All）；</li><li><strong>轻量微调（如 LoRA）</strong> 和 <strong>推理服务</strong>易受 <strong>Host（CPU/通信）限制</strong>。</li></ul></blockquote><h3 id="二、性能优化方法论三大维度" tabindex="-1">二、性能优化方法论三大维度 <a class="header-anchor" href="#二、性能优化方法论三大维度" aria-label="Permalink to “二、性能优化方法论三大维度”">​</a></h3><h4 id="_1-计算优化-提升算力利用率" tabindex="-1">1. <strong>计算优化（提升算力利用率）</strong> <a class="header-anchor" href="#_1-计算优化-提升算力利用率" aria-label="Permalink to “1. 计算优化（提升算力利用率）”">​</a></h4><ul><li><strong>算子融合</strong>： <ul><li><code>FlashAttention</code>、<code>Fused RotaryEmbedding</code>、<code>Fused RMSNorm</code>、<code>Fused SwiGLU</code></li><li>MoE 专用：<code>Fused Token Permute/Unpermute</code></li></ul></li><li><strong>算法优化</strong>： <ul><li>使用高效 GEMM/BMM 实现</li><li>非连续内存 → 连续内存（提升访存效率）</li><li>Vector 指令优化、AICPU 算子卸载</li></ul></li><li><strong>流水线优化</strong>： <ul><li>多流水并行下发</li><li>FA（FlashAttention）推理引擎 + 融合下发</li></ul></li></ul><h4 id="_2-显存优化-降低峰值显存-提升容量" tabindex="-1">2. <strong>显存优化（降低峰值显存，提升容量）</strong> <a class="header-anchor" href="#_2-显存优化-降低峰值显存-提升容量" aria-label="Permalink to “2. 显存优化（降低峰值显存，提升容量）”">​</a></h4><ul><li><strong>重计算（Recomputation）</strong>： <ul><li>激活函数重计算（节省激活值存储）</li><li>全重计算（Full Recompute）</li><li><strong>Recompute in Advance</strong>：提前重计算，掩盖通信延迟，减少 Pipeline Bubble</li></ul></li><li><strong>显存复用与交换</strong>： <ul><li>参数副本复用（时分复用）</li><li>Swap Attention（用主机内存换显存）</li></ul></li><li><strong>精度优化</strong>： <ul><li>O2 BF16 Optimizer（半精度优化器状态）</li></ul></li></ul><h4 id="_3-通信优化-通算掩盖-带宽提升" tabindex="-1">3. <strong>通信优化（通算掩盖 &amp; 带宽提升）</strong> <a class="header-anchor" href="#_3-通信优化-通算掩盖-带宽提升" aria-label="Permalink to “3. 通信优化（通算掩盖 &amp; 带宽提升）”">​</a></h4><ul><li><strong>通算掩盖（Overlap Computation &amp; Communication）</strong>： <ul><li>MC2：在线性层做通信掩盖（TP/SP 场景）</li><li>梯度 Reduce 与参数更新重叠</li><li>权重 All-Gather 与前向计算重叠</li></ul></li><li><strong>MoE 通信优化</strong>： <ul><li><code>--moe-permutation-async-comm</code>（异步通信）</li><li>Dispatcher 选择：<code>allgather</code>（适合小专家） vs <code>alltoall</code>（适合大专家）</li><li>EP（Expert Parallel）通信隐藏</li></ul></li><li><strong>并行策略优化</strong>： <ul><li>高维张量并行（切分 1D-TP 通信域，提升 Cube 利用率）</li><li>最小 DP 组优化、多机通信优化</li></ul></li></ul><h3 id="三、并行策略对比分析" tabindex="-1">三、并行策略对比分析 <a class="header-anchor" href="#三、并行策略对比分析" aria-label="Permalink to “三、并行策略对比分析”">​</a></h3><table tabindex="0"><thead><tr><th>并行方式</th><th>优点</th><th>缺点</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Tensor Parallel (TP)</strong></td><td>降低单卡显存</td><td>TP 域内通信开销大，Cube 效率下降</td><td>稠密模型，大 MatMul</td></tr><tr><td><strong>Sequence Parallel (SP)</strong></td><td>切分 LayerNorm/Dropout 显存</td><td>需配合 TP，通信复杂</td><td>长序列训练</td></tr><tr><td><strong>Pipeline Parallel (PP)</strong></td><td>降低静态显存</td><td>Bubble（空泡）、计算/显存不均衡</td><td>模型层数多</td></tr><tr><td><strong>Virtual PP</strong></td><td>减少 Bubble</td><td>Send/Recv 次数增加，动态显存上升</td><td>深层模型</td></tr><tr><td><strong>Expert Parallel (EP)</strong></td><td>切分 MoE 专家，降显存</td><td>专家负载不均 → 显存瓶颈</td><td>MoE 模型</td></tr><tr><td><strong>Distributed Optimizer (ZeRO-DP)</strong></td><td>降低优化器状态 &amp; 参数副本内存</td><td>通信量增加</td><td>所有场景（尤其微调）</td></tr></tbody></table><blockquote><p>💡 <strong>组合建议</strong>：</p><ul><li>MoE 模型常用 <strong>TP + EP + DP</strong> 混合并行；</li><li>长序列场景引入 <strong>Ring/Ulysses SP</strong>；</li><li>使用 <strong>Noop Layer</strong> 或 <strong>Dynamic PP</strong> 手动均衡 PP Stage。</li></ul></blockquote><h3 id="四、mindspeed-llm-支持的关键特性-ascend-平台" tabindex="-1">四、MindSpeed LLM 支持的关键特性（Ascend 平台） <a class="header-anchor" href="#四、mindspeed-llm-支持的关键特性-ascend-平台" aria-label="Permalink to “四、MindSpeed LLM 支持的关键特性（Ascend 平台）”">​</a></h3><h4 id="🔹-长序列优化" tabindex="-1">🔹 长序列优化 <a class="header-anchor" href="#🔹-长序列优化" aria-label="Permalink to “🔹 长序列优化”">​</a></h4><ul><li>Ring Attention（Megatron-Ring）</li><li>Ulysses SP（DeepSpeed-Ulysses）</li><li>混合长序列并行（Ring + Ulysses）</li><li>Adaptive-CP（序列重映射 &amp; 调度寻优）</li></ul><h4 id="🔹-moe-优化" tabindex="-1">🔹 MoE 优化 <a class="header-anchor" href="#🔹-moe-优化" aria-label="Permalink to “🔹 MoE 优化”">​</a></h4><ul><li>AllGather / All2All Dispatcher 选择</li><li>异步通信（<code>--moe-permutation-async-comm</code>）</li><li>EP 通信隐藏</li></ul><h4 id="🔹-通用加速" tabindex="-1">🔹 通用加速 <a class="header-anchor" href="#🔹-通用加速" aria-label="Permalink to “🔹 通用加速”">​</a></h4><ul><li>Noop Layer（插入空操作层，均衡 PP 计算）</li><li>Dynamic PP（手动指定每 Stage 层数）</li><li>Recompute in Advance（解耦反向依赖，降 Bubble）</li></ul><h4 id="🔹-显存优化" tabindex="-1">🔹 显存优化 <a class="header-anchor" href="#🔹-显存优化" aria-label="Permalink to “🔹 显存优化”">​</a></h4><ul><li>参数副本复用、Swap Attention、激活重计算、BF16 优化器</li></ul><h4 id="🔹-融合算子-fused-kernels" tabindex="-1">🔹 融合算子（Fused Kernels） <a class="header-anchor" href="#🔹-融合算子-fused-kernels" aria-label="Permalink to “🔹 融合算子（Fused Kernels）”">​</a></h4><ul><li>FlashAttention、Fused Ring Attention Update（长序列）</li><li>Fused Token Permute/Unpermute（MoE）</li><li>GMM（Grouped MatMul，用于小专家 MoE）</li><li>Matmul Add（梯度累积）</li><li>Fused SwiGLU / Rotary / RMSNorm（通用）</li></ul><h3 id="五、总结-性能优化-暗线" tabindex="-1">五、总结：性能优化“暗线” <a class="header-anchor" href="#五、总结-性能优化-暗线" aria-label="Permalink to “五、总结：性能优化“暗线””">​</a></h3><blockquote><p><strong>“识别瓶颈 → 选择策略 → 应用特性”</strong></p><ul><li>先判断是 <strong>Device Bound</strong> 还是 <strong>Host Bound</strong>；</li><li>再根据 <strong>模型结构</strong>（稠密/MoE）、<strong>任务类型</strong>（预训练/微调/推理）、<strong>序列长度</strong> 选择并行策略；</li><li>最后启用 MindSpeed 对应的 <strong>加速特性</strong> 与 <strong>融合算子</strong>，实现端到端优化。</li></ul></blockquote>',29)])])}const m=e(i,[["render",o]]);export{g as __pageData,m as default};
